#endif

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <cuda_runtime.h>

#include "./../main.h"
#include "./kernel_gpu_opencl_wrapper.h"

extern void kernel_gpu_cuda_wrapper(par_str parms_cpu,
								dim_str dim_cpu,
								box_str* box_cpu,
								FOUR_VECTOR* rv_cpu,
								fp* qv_cpu,
								FOUR_VECTOR* fv_cpu);

void 
kernel_gpu_opencl_wrapper(	par_str par_cpu,
							dim_str dim_cpu,
							box_str* box_cpu,
							FOUR_VECTOR* rv_cpu,
							fp* qv_cpu,
							FOUR_VECTOR* fv_cpu)
{
	cudaError_t error;

	box_str* d_box_gpu;
	FOUR_VECTOR* d_rv_gpu;
	fp* d_qv_gpu;
	FOUR_VECTOR* d_fv_gpu;

	size_t box_mem = dim_cpu.box_mem;
	size_t space_mem = dim_cpu.space_mem;
	size_t space_mem2 = dim_cpu.space_mem2;

	// Allocate device memory
	error = cudaMalloc((void**)&d_box_gpu, box_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_box_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMalloc((void**)&d_rv_gpu, space_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_rv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMalloc((void**)&d_qv_gpu, space_mem2);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_qv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMalloc((void**)&d_fv_gpu, space_mem);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMalloc d_fv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	// Copy data from host to device
	error = cudaMemcpy(d_box_gpu, box_cpu, box_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_box_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMemcpy(d_rv_gpu, rv_cpu, space_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_rv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMemcpy(d_qv_gpu, qv_cpu, space_mem2, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_qv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaMemcpy(d_fv_gpu, fv_cpu, space_mem, cudaMemcpyHostToDevice);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy d_fv_gpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	// Launch kernel
	dim3 blockDim(NUMBER_THREADS);
	dim3 gridDim(dim_cpu.number_boxes);

	kernel_gpu_opencl<<<gridDim, blockDim>>>(par_cpu, dim_cpu, d_box_gpu, d_rv_gpu, d_qv_gpu, d_fv_gpu);
	error = cudaGetLastError();
	if (error != cudaSuccess) {
		fprintf(stderr, "Kernel launch failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	error = cudaDeviceSynchronize();
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaDeviceSynchronize failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	// Copy results back to host
	error = cudaMemcpy(fv_cpu, d_fv_gpu, space_mem, cudaMemcpyDeviceToHost);
	if (error != cudaSuccess) {
		fprintf(stderr, "cudaMemcpy fv_cpu failed: %s\n", cudaGetErrorString(error));
		exit(EXIT_FAILURE);
	}

	// Free device memory
	cudaFree(d_box_gpu);
	cudaFree(d_rv_gpu);
	cudaFree(d_qv_gpu);
	cudaFree(d_fv_gpu);
}

#ifdef __cplusplus
}
#endif
